import './Home.css';
import tshirt from '../tshirt.webp';
import shirt from '../shirt.webp';
import pant from '../pant.webp';
// import background from '../background.jpg';



function Home() {
  return (
    <div className="home-container">
      <header className="home-header">

        <h1>CREWS</h1>
        <p>Style starts here! Discover our latest collection now.</p>
        <img src={background} className='back'></img>
      </header>

      <section className="products-section">
        <h2>🛍️ Featured Products</h2>
        <div className="product-list">
          <div className="product-card">
            <img src={tshirt}alt="T-Shirt" />
            <h3>Cool T-Shirt</h3>
            <p>₹499</p>
          </div>
          <div className="product-card">
            <img src={shirt} alt="Dress" />
            <h3>Stylish Dress</h3>
            <p>₹999</p>
          </div>
          <div className="product-card">
            <img src={pant} alt="Jeans" />
            <h3>Classic Jeans</h3>
            <p>₹799</p>
          </div>
        </div>
      </section>
    </div>
  );
}

export default Home;
